set_module_param() {
	module="$1"
	param="$2"
	value="$3"
	path="/sys/module/$module/parameters/$param"
	if [ ! -e "$path" ]; then
		echo "missing module parameter $module:$param" >&2
		exit 1
	fi
	printf '%s\n' "$value" > "$path"
}

