			nq_cyclic_burst_bits="$NQ_DMA_CYCLIC_BURST_BITS" \
			nq_force_descriptor_residue="$NQ_DMA_FORCE_DESCRIPTOR_RESIDUE" \
			nq_audio_tone="$NQ_DMA_AUDIO_TONE" \
			nq_audio_tone_rate="$NQ_DMA_AUDIO_TONE_RATE" \
			nq_audio_tone_freq="$NQ_DMA_AUDIO_TONE_FREQ" \
			nq_audio_tone_amp="$NQ_DMA_AUDIO_TONE_AMP" \
			nq_audio_tone_channel="$NQ_DMA_AUDIO_TONE_CHANNEL" \
			nq_audio_tone_dev_addr="$NQ_DMA_AUDIO_TONE_DEV_ADDR" \
			nq_audio_tone_no_irq="$NQ_DMA_AUDIO_TONE_NO_IRQ" \
			nq_audio_tone_fake_period="$NQ_DMA_AUDIO_TONE_FAKE_PERIOD" \
			nq_force_lch_sig="$NQ_DMA_FORCE_LCH_SIG" \
			nq_force_lch="$NQ_DMA_FORCE_LCH" \
			nq_force_rw_priority="$NQ_DMA_FORCE_RW_PRIORITY"
		set_module_param omap_dma nq_legacy_cyclic_sync "$NQ_DMA_LEGACY_CYCLIC_SYNC"
		set_module_param omap_dma nq_legacy_cyclic_burst "$NQ_DMA_LEGACY_CYCLIC_BURST"
		set_module_param omap_dma nq_legacy_cyclic_pack "$NQ_DMA_LEGACY_CYCLIC_PACK"
		set_module_param omap_dma nq_legacy_cyclic_block_irq "$NQ_DMA_LEGACY_CYCLIC_BLOCK_IRQ"
		set_module_param omap_dma nq_dump_cyclic "$NQ_DMA_DUMP_CYCLIC"
